urlset:

  {{ .Site.BaseURL }}
  {{ now.Format "2006-01-02" }}
  daily
  1.0

{{- range where .Site.RegularPages "Type" "in" .Site.Params.mainSections }}
{{- if not .Draft }}

  {{ .Permalink }}
  {{ .Lastmod.Format "2006-01-02" }}
  weekly
  0.8

{{- end }}
{{- end }}
{{- range where .Site.Pages "Kind" "page" }}
{{- if and (ne .Type "posts") (ne .RelPermalink "/") (not .Draft) }}

  {{ .Permalink }}
  {{ .Lastmod.Format "2006-01-02" }}
  monthly
  0.5

{{- end }}
{{- end }}
